const items = $input.all();
const config = $('Set Weekly Config').first().json;
const weekDate = config.weekDate;
const normalized = [];

for (const item of items) {
  const d = item.json;
  let source = 'web', competitorName = 'Unknown', content = '', itemUrl = '', pubDate = weekDate;

  if (d.link || d.guid || d.pubDate) {
    source = 'rss';
    competitorName = 'Industry';
    content = (d.contentSnippet || d.content || d.description || '').substring(0, 800);
    itemUrl = d.link || d.guid || '';
    pubDate = d.pubDate || weekDate;
  } else {
    const title = (d.pageTitle || '').toLowerCase();
    if (title.includes((config.competitor1Name || '').toLowerCase())) {
      competitorName = config.competitor1Name; itemUrl = config.competitor1Url;
    } else if (title.includes((config.competitor2Name || '').toLowerCase())) {
      competitorName = config.competitor2Name; itemUrl = config.competitor2Url;
    } else {
      competitorName = config.competitor3Name || 'Unknown'; itemUrl = config.competitor3Url || '';
    }
    const parts = [d.pageTitle, d.h1Headings, d.pricingContent, d.featureContent, d.mainContent].filter(Boolean);
    content = parts.join(' | ').substring(0, 1200);
  }

  if (content.trim()) {
    normalized.push({ source, competitor: competitorName, title: d.title || d.pageTitle || 'No Title', content: content.trim(), url: itemUrl, pubDate, weekDate });
  }
}

return [{ json: { allData: normalized, totalItems: normalized.length, weekDate, collectedAt: new Date().toISOString() } }];

const items = $input.all();
const config = $('Set Weekly Config').first().json;

let currentData = null;
const previousRows = [];

for (const item of items) {
  const d = item.json;
  if (d.allData) { currentData = d; }
  else if (d.weekDate === config.previousWeekDate) { previousRows.push(d); }
}

if (!currentData) { currentData = { allData: [], totalItems: 0, weekDate: config.weekDate }; }

const comparisonContext = previousRows.length > 0
  ? `PREVIOUS WEEK DATA (${config.previousWeekDate}):\n${JSON.stringify(previousRows.slice(0, 15), null, 2)}`
  : 'No previous week data available (first run or data gap).';

const dataForAgent = currentData.allData.slice(0, 30).map(item => ({
  source: item.source,
  competitor: item.competitor,
  title: item.title.substring(0, 100),
  content: item.content.substring(0, 600),
  url: item.url,
  pubDate: item.pubDate
}));

return [{ json: {
  weekDate: config.weekDate,
  previousWeekDate: config.previousWeekDate,
  yourCompany: config.yourCompanyName,
  industry: config.yourIndustry,
  groqModel: config.groqModel,
  maxTokens: config.maxTokens,
  currentData: dataForAgent,
  totalSourcesCollected: currentData.totalItems,
  comparisonContext,
  previousDataAvailable: previousRows.length > 0
} }];

const d = $input.first().json;

const SYSTEM_PROMPT = `You are the Scout Agent in a Multi-Agent Competitor Intelligence System for ${d.yourCompany} in the ${d.industry} space.

Your mission: Organize raw competitor data collected this week (${d.weekDate}) into a structured intelligence brief.

TASKS:
1. Categorize findings by competitor
2. Flag significant changes: new features, pricing shifts, messaging updates, product launches
3. Compare with previous week if available
4. Assess data completeness

Respond ONLY with valid JSON:
{
  "intelligence_week": "${d.weekDate}",
  "sources_analyzed": <number>,
  "competitors": [
    {
      "name": "<name>",
      "key_changes_this_week": ["change"],
      "new_features_detected": ["feature"],
      "pricing_signals": "<pricing or 'no data'>",
      "content_themes": ["theme"],
      "market_positioning": "<positioning>",
      "confidence": "high/medium/low",
      "vs_last_week": "<change vs prev or 'no comparison data'>"
    }
  ],
  "market_signals": [{"signal": "<desc>", "source": "<src>", "significance": "high/medium/low", "potential_impact_on_us": "<impact>"}],
  "top_3_developments": [{"rank": 1, "development": "<dev>", "urgency": "high/medium/low"}],
  "week_summary": "<2-3 sentence summary>"
}`;

return [{ json: {
  requestPayload: {
    model: d.groqModel,
    messages: [
      { role: 'system', content: SYSTEM_PROMPT },
      { role: 'user', content: `CURRENT WEEK DATA (${d.weekDate}):\n${JSON.stringify(d.currentData, null, 2)}\n\n${d.comparisonContext}` }
    ],
    temperature: 0.2,
    max_tokens: d.maxTokens
  },
  passThrough: d
} }];

const response = $input.first().json;
const passThrough = $('Prepare Scout Request').first().json.passThrough;
const rawContent = response.choices?.[0]?.message?.content || '';
let parsed = null;
try { const m = rawContent.match(/\{[\s\S]*\}/); if (m) parsed = JSON.parse(m[0]); } catch(e) {}
return [{ json: { ...passThrough, scoutBrief: parsed || { raw: rawContent.substring(0, 1000) }, tokenUsage: { scout: response.usage?.total_tokens || 0 }, agentChain: ['Scout'] } }];

const d = $input.first().json;

const SYSTEM_PROMPT = `You are the Analyst Agent in a Multi-Agent Competitor Intelligence System for ${d.yourCompany} in the ${d.industry} space.

You receive a Scout brief and produce deep competitive analysis.

Your role:
1. Analyze positioning and strategy shifts with evidence
2. Assess product development trajectories and feature velocity
3. Identify competitive threats (1-10 severity) and opportunities
4. Predict likely next moves per competitor

Respond ONLY with valid JSON:
{
  "analysis_date": "${d.weekDate}",
  "competitive_landscape": {"overall_intensity": "high/medium/low", "market_phase": "growth/maturity/disruption", "key_dynamics": ["dynamic"]},
  "competitor_deep_dives": [{"competitor": "<name>", "strategic_direction": "<dir>", "feature_velocity": "accelerating/steady/slowing", "pricing_strategy": "<strategy>", "predicted_next_moves": ["move (confidence: high)"], "evidence_base": ["evidence"]}],
  "threat_matrix": [{"threat": "<desc>", "competitor": "<name>", "severity": 1, "timeline": "immediate/3-6 months/6-12 months", "evidence": "<data>"}],
  "opportunity_matrix": [{"opportunity": "<desc>", "type": "gap/positioning/timing", "potential_impact": "high/medium/low", "evidence": "<why>", "capture_window": "<window>"}],
  "key_insights": ["insight 1", "insight 2"],
  "analyst_confidence": "high/medium/low"
}`;

return [{ json: {
  requestPayload: {
    model: d.groqModel,
    messages: [
      { role: 'system', content: SYSTEM_PROMPT },
      { role: 'user', content: `Analyze this Scout brief:\n${JSON.stringify(d.scoutBrief, null, 2)}` }
    ],
    temperature: 0.3,
    max_tokens: d.maxTokens
  },
  passThrough: d
} }];

const response = $input.first().json;
const passThrough = $('Prepare Analyst Request').first().json.passThrough;
const rawContent = response.choices?.[0]?.message?.content || '';
let parsed = null;
try { const m = rawContent.match(/\{[\s\S]*\}/); if (m) parsed = JSON.parse(m[0]); } catch(e) {}
return [{ json: { ...passThrough, analystReport: parsed || { raw: rawContent.substring(0, 1000) }, tokenUsage: { ...passThrough.tokenUsage, analyst: response.usage?.total_tokens || 0 }, agentChain: [...(passThrough.agentChain||[]), 'Analyst'] } }];

const d = $input.first().json;

const SYSTEM_PROMPT = `You are the Critic Agent in a Multi-Agent Competitor Intelligence System for ${d.yourCompany}.

Your role is quality control and intellectual rigor. Challenge and refine the Analyst's assessment.

CRITIQUE FRAMEWORK:
1. Flag claims lacking evidence from the Scout brief
2. Detect confirmation bias and overconfidence
3. Offer alternative interpretations for competitor behavior
4. Recalibrate threat/opportunity scores with weak evidence
5. Identify angles the Analyst missed

Respond ONLY with valid JSON:
{
  "critique_date": "${d.weekDate}",
  "overall_analysis_quality": "excellent/good/fair/poor",
  "quality_score": 1,
  "strengths": ["strength"],
  "critical_issues": [{"issue": "<issue>", "original_claim": "<claim>", "why_problematic": "<why>", "severity": "high/medium/low"}],
  "unsupported_claims": [{"claim": "<claim>", "required_evidence": "<what's needed>"}],
  "alternative_interpretations": [{"original_finding": "<finding>", "alternative": "<alt>", "plausibility": "high/medium/low"}],
  "recalibrated_threats": [{"threat": "<desc>", "analyst_severity": 1, "critic_severity": 1, "rationale": "<why>"}],
  "missed_angles": ["angle"],
  "validated_findings": ["finding with strong evidence"]
}`;

return [{ json: {
  requestPayload: {
    model: d.groqModel,
    messages: [
      { role: 'system', content: SYSTEM_PROMPT },
      { role: 'user', content: `Review this intelligence chain:\n\nSCOUT:\n${JSON.stringify(d.scoutBrief, null, 2)}\n\nANALYST:\n${JSON.stringify(d.analystReport, null, 2)}` }
    ],
    temperature: 0.4,
    max_tokens: d.maxTokens
  },
  passThrough: d
} }];

const response = $input.first().json;
const passThrough = $('Prepare Critic Request').first().json.passThrough;
const rawContent = response.choices?.[0]?.message?.content || '';
let parsed = null;
try { const m = rawContent.match(/\{[\s\S]*\}/); if (m) parsed = JSON.parse(m[0]); } catch(e) {}
return [{ json: { ...passThrough, critique: parsed || { raw: rawContent.substring(0, 1000) }, tokenUsage: { ...passThrough.tokenUsage, critic: response.usage?.total_tokens || 0 }, agentChain: [...(passThrough.agentChain||[]), 'Critic'] } }];

const d = $input.first().json;

const SYSTEM_PROMPT = `You are the Strategist Agent in a Multi-Agent Competitor Intelligence System for ${d.yourCompany} in the ${d.industry} space.

Synthesize the full intelligence chain into actionable strategic recommendations.

FRAMEWORK:
1. IMMEDIATE (0-2 weeks): Urgent threat responses
2. SHORT-TERM (1-3 months): Tactical competitive moves
3. MEDIUM-TERM (3-6 months): Strategic opportunity capture

Respond ONLY with valid JSON:
{
  "strategy_date": "${d.weekDate}",
  "strategic_summary": "<2-3 sentence executive summary>",
  "this_weeks_top_priority": {"action": "<action>", "rationale": "<why>", "deadline": "<date>", "owner": "<team/role>"},
  "immediate_actions": [{"action": "<action>", "rationale": "<why>", "evidence_basis": "<intel>", "timeline": "<time>", "priority": 1, "success_metric": "<metric>", "estimated_effort": "low/medium/high"}],
  "short_term_strategy": [{"initiative": "<init>", "objective": "<obj>", "competitive_rationale": "<rationale>", "priority": 1}],
  "opportunities_to_capture": [{"opportunity": "<opp>", "capture_method": "<how>", "window": "<how long>", "estimated_impact": "high/medium/low"}],
  "risks_to_mitigate": [{"risk": "<risk>", "mitigation": "<action>", "severity": 1}],
  "kpis_to_monitor_next_week": ["KPI"],
  "signals_to_watch": ["signal"]
}`;

return [{ json: {
  requestPayload: {
    model: d.groqModel,
    messages: [
      { role: 'system', content: SYSTEM_PROMPT },
      { role: 'user', content: `Build strategy from:\n\nSCOUT:\n${JSON.stringify(d.scoutBrief, null, 2)}\n\nANALYST:\n${JSON.stringify(d.analystReport, null, 2)}\n\nCRITIC:\n${JSON.stringify(d.critique, null, 2)}` }
    ],
    temperature: 0.5,
    max_tokens: d.maxTokens
  },
  passThrough: d
} }];

const response = $input.first().json;
const passThrough = $('Prepare Strategist Request').first().json.passThrough;
const rawContent = response.choices?.[0]?.message?.content || '';
let parsed = null;
try { const m = rawContent.match(/\{[\s\S]*\}/); if (m) parsed = JSON.parse(m[0]); } catch(e) {}
return [{ json: { ...passThrough, strategy: parsed || { raw: rawContent.substring(0, 1000) }, tokenUsage: { ...passThrough.tokenUsage, strategist: response.usage?.total_tokens || 0 }, agentChain: [...(passThrough.agentChain||[]), 'Strategist'] } }];

const response = $input.first().json;
const d = $('Prepare Writer Request').first().json.passThrough;
const markdownReport = response.choices?.[0]?.message?.content || '# Report Generation Failed';
const writerTokens = response.usage?.total_tokens || 0;
const totalTokens = Object.values(d.tokenUsage || {}).reduce((s, v) => s + (typeof v === 'number' ? v : 0), 0) + writerTokens;

const firstParagraphs = markdownReport.split('\n').slice(0, 20).join('\n');
const execMatch = markdownReport.match(/## Executive Summary\n([\s\S]*?)\n##/);
const execSummary = execMatch ? execMatch[1].trim().substring(0, 500) : firstParagraphs.substring(0, 500);

const discordSummary = `**Weekly Competitor Intelligence - ${d.weekDate}**\n\n${execSummary.substring(0, 1400)}...\n\n*Agents: Scout→Analyst→Critic→Strategist→Writer | Tokens: ${totalTokens} (Groq Free)*`;
const telegramSummary = `*Weekly Intelligence - ${d.weekDate}*\n\n${execSummary.substring(0, 800)}\n\n_Full report in Google Drive | Tokens: ${totalTokens}_`;

const config = $('Set Weekly Config').first().json;

return [{ json: {
  markdownReport,
  discordSummary,
  telegramSummary,
  weekDate: d.weekDate,
  reportTitle: d.weekDate + ' Competitor Intelligence Report',
  sheetsRow: {
    weekDate: d.weekDate,
    reportTitle: d.weekDate + ' Intelligence Report',
    agentsCompleted: [...(d.agentChain||[]), 'Writer'].join(', '),
    totalTokensUsed: totalTokens,
    generatedAt: new Date().toISOString()
  },
  googleDriveFolderId: config.googleDriveFolderId,
  googleSheetsId: config.googleSheetsId,
  discordWebhookUrl: config.discordWebhookUrl,
  telegramChatId: config.telegramChatId,
  totalTokensUsed: totalTokens
} }];

const item = $input.first();
const content = item.json.markdownReport || '# No Report Generated';
const fileName = (item.json.reportTitle || 'Competitor Intelligence Report') + '.md';

return [{
  json: item.json,
  binary: {
    data: await this.helpers.prepareBinaryData(
      Buffer.from(content, 'utf-8'),
      fileName,
      'text/markdown'
    )
  }
}];

